defineOptions({ name: 'SkillDetail' })

type SkillDetail = { id: string; name: string; status: string; version: string; updatedAt: string; owner: string; scene: string; description: string; skillPoints: string[]; docRaw: string; boundaries: string[] }
const route = useRoute()
const router = useRouter()
const skillDetails: Record<string, SkillDetail> = {
  'skill-report-writer': { id: 'skill-report-writer', name: '报告生成 Skill', status: '启用', version: 'v0.1.0', updatedAt: '2026-04-20 11:00', owner: 'AI 平台 / 报告生成 Agent', scene: '安全生产报告、整改报告、巡检分析报告', description: '把报告生成能力作为一份可阅读、可维护的 Skill 文档承接，用于说明能力边界、适用场景、生成规则和演示路径。', skillPoints: ['报告模板选择', 'Markdown 报告生成', 'NL2SQL 数据引用', '失败兜底提示', '右侧文档预览'], docRaw: '# 报告生成 Skill\n\n## 能力说明\n\n用于将用户输入、报告模板和可选 NL2SQL 数据结果组合为结构化 Markdown 报告。\n\n## 使用路径\n\n- 在首页选择「报告生成 Agent」\n- 输入报告需求后回车\n- 系统创建 Markdown 文档并打开右侧预览\n\n## 评审关注\n\n- 报告分屏不是选择 Agent 后立即出现，而是在开始生成后打开\n- 右侧预览可以关闭，关闭后恢复单屏\n- 当前阶段以 Markdown 文档为主，不做复杂 Word 在线排版', boundaries: ['不做复杂在线文档编辑器', '不做复杂 Word 排版', '不做模板市场', '不做跨系统多数据融合'] },
  'skill-nl2sql-governance': { id: 'skill-nl2sql-governance', name: 'NL2SQL 增强 Skill', status: '启用', version: 'v0.1.0', updatedAt: '2026-04-20 11:20', owner: 'AI 平台 / NL2SQL Agent', scene: '自然语言问数、指标解释、查询口径兜底', description: '将 NL2SQL 增强能力整理成 Skill 文档，用于描述 Case、专有名词和单数据源如何参与问数链路。', skillPoints: ['Good / Bad Case 参考', '专有名词别名映射', '单 JDBC 数据源', '查询口径解释', '失败提示兜底'], docRaw: '# NL2SQL 增强 Skill\n\n## 能力说明\n\n用于在问数前读取 Case、术语和单数据源配置，辅助生成 SQL 与口径解释。\n\n## 使用路径\n\n- 在系统设置中维护 NL2SQL 配置\n- 在首页通过 NL2SQL Agent 发起问数\n- Agent 根据 Case、术语、数据源状态给出查询说明\n\n## 本期范围\n\n只做单数据源，不做多数据源和跨库查询。', boundaries: ['不做多数据源', '不做跨库查询', '不做自动 SQL 优化', '不做多轮复杂推理'] },
}
const detail = computed(() => skillDetails[String(route.params.id)] || skillDetails['skill-report-writer'])
function escapeHtml(text: string) { return text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;') }
function renderMarkdown(text: string) { return escapeHtml(text).replace(/^# (.*)$/gm, '<h1 class="mb-3 text-2xl font-bold text-slate-950">$1</h1>').replace(/^## (.*)$/gm, '<h2 class="mb-2 mt-5 text-base font-semibold text-slate-900">$1</h2>').replace(/^- (.*)$/gm, '<li class="ml-5 list-disc text-sm leading-7 text-slate-700">$1</li>').replace(/\n/g, '<br />') }
</script>

