    </div>
    <div class="grid gap-5 xl:grid-cols-[minmax(0,1fr)_360px]"><section class="space-y-5"><div class="rounded-[28px] border border-sky-200/70 bg-white/85 p-6 shadow-[0_18px_44px_rgba(14,116,144,0.06)]"><div class="mb-4 flex items-center gap-2 text-sm font-semibold text-slate-900"><FileText class="h-4 w-4 text-sky-600" /> Skill.md 文档</div><article class="rounded-2xl bg-gradient-to-br from-white to-sky-50/70 p-5 text-slate-700 ring-1 ring-sky-200/70" v-html="renderMarkdown(detail.docRaw)" /></div></section><aside class="space-y-5"><div class="rounded-[24px] border border-sky-200/70 bg-white/85 p-5 shadow-[0_18px_44px_rgba(14,116,144,0.06)]"><div class="mb-4 flex items-center gap-2 text-sm font-semibold text-slate-900"><Lightbulb class="h-4 w-4 text-sky-600" /> 核心技能点</div><div class="space-y-2"><div v-for="item in detail.skillPoints" :key="item" class="flex items-start gap-2 rounded-xl bg-sky-50/80 px-3 py-2 text-xs leading-5 text-slate-700 ring-1 ring-sky-100"><CheckCircle2 class="mt-0.5 h-3.5 w-3.5 shrink-0 text-sky-600" /> {{ item }}</div></div></div><div class="rounded-[24px] border border-sky-200/70 bg-white/85 p-5"><div class="mb-4 flex items-center gap-2 text-sm font-semibold text-slate-900"><ShieldCheck class="h-4 w-4 text-sky-600" /> 适用场景</div><div class="rounded-2xl bg-sky-50/80 p-4 text-sm leading-6 text-slate-700 ring-1 ring-sky-200/70">{{ detail.scene }}</div></div><div class="rounded-[24px] border border-amber-200 bg-amber-50/80 p-5"><div class="mb-4 flex items-center gap-2 text-sm font-semibold text-amber-900"><AlertTriangle class="h-4 w-4" /> 本期边界</div><div class="space-y-2"><div v-for="item in detail.boundaries" :key="item" class="flex items-start gap-2 rounded-xl bg-white/70 px-3 py-2 text-xs leading-5 text-amber-900 ring-1 ring-amber-100"><CheckCircle2 class="mt-0.5 h-3.5 w-3.5 shrink-0" /> {{ item }}</div></div></div></aside></div>
  </div>
